import type { Lesson } from "./lesson-types";

// AUTO-GENERATED by scripts/build-lessons.mts. Do not edit by hand.
// Original study lessons authored to the ATI TEAS 7 skill taxonomy (skills.ts).
export const LESSONS: Lesson[] = [
  {"section":"READING","topic":"key-ideas-details","title":"Key Ideas & Details","intro":"This topic tests whether you can pull the central meaning out of a passage and track its supporting details: finding the main idea, summarizing, drawing logical conclusions, following directions and sequences, and locating exact information in text, printed documents, and graphics.","sections":[{"heading":"Topic vs. Main Idea vs. Supporting Detail","body":"These three terms sit at the heart of this whole section, and the test loves to make you tell them apart.\n\n- Topic: the general subject in a word or short phrase. Answers \"What is this about?\" Example: \"hand hygiene.\"\n- Main idea: the single most important point the author makes about the topic, usually a full sentence. Answers \"What does the author want me to understand about it?\" Example: \"Consistent handwashing is the most effective way to prevent the spread of infection.\"\n- Supporting detail: a fact, example, statistic, or reason that backs up the main idea. Example: \"Studies show proper handwashing reduces respiratory illness by about 20 percent.\"\n\nThink of it as a funnel: topic (broad) narrows to main idea (the point) which is propped up by details (the evidence)."},{"heading":"How to find the main idea on the test","body":"The main idea is often stated in a topic sentence, frequently the first or last sentence of a paragraph. But sometimes it is implied, and you have to assemble it from the details.\n\nA reliable trick: after reading, ask \"If I could keep only one sentence, which one would the rest of the passage be explaining or proving?\" That sentence (or your paraphrase of it) is the main idea.\n\nWatch the trap answers. Wrong choices on main-idea questions are usually one of three types: too narrow (a single detail dressed up as the point), too broad (covers more than the passage actually says), or off-topic (true-sounding but not in the text). The right answer covers the whole passage without going beyond it."},{"heading":"Summarizing a multi-paragraph text","body":"A summary restates the main points of an entire passage briefly and in your own words. It is not a copy of the first sentence and not a list of every detail.\n\nA good summary includes the overall main idea plus the key supporting point from each major paragraph, and it leaves out minor examples, opinions, and repetition.\n\nOn the test, the best summary answer is accurate (nothing added that the author did not say), complete (no major point missing), and balanced (it does not overstate one paragraph while ignoring the rest). Reject any choice that introduces a new claim or that zooms in on just one paragraph."},{"heading":"Inferring logical conclusions","body":"An inference is a conclusion you reach using evidence in the text plus reason, even though the author never states it outright. The key phrase to remember: a valid inference must be supported by the passage, not just plausible in real life.\n\nLook for question stems like \"It can be concluded that,\" \"The passage suggests,\" \"The author would most likely agree that,\" or \"Most likely.\"\n\nMini-example: A passage says, \"By the time the clinic opened at 8 a.m., the waiting room was already full, and staff had to bring in extra chairs.\" You can reasonably infer that demand for the clinic exceeds its seating capacity. You cannot infer that the clinic is understaffed, because nothing in the text addresses staffing levels. If you have to import facts the passage never gave you, it is not a safe inference."},{"heading":"Comprehending written directions","body":"Some questions give you a set of instructions (a recipe, a medication schedule, an assembly or procedure) and ask what to do, in what order, or what happens if a step is skipped.\n\nRead every step before answering, and pay close attention to signal words: \"before,\" \"after,\" \"until,\" \"unless,\" \"if,\" \"do not,\" and \"once.\" These small words control the logic.\n\nMini-example: \"Shake the suspension well. Do not take on an empty stomach. Wait at least 30 minutes after eating before measuring the dose.\" Question: Can you take the dose immediately after a meal? No. The directions say to wait at least 30 minutes after eating, so taking it right away violates a step. Conditional words like \"do not\" and \"at least\" are exactly what the test checks."},{"heading":"Locating specific information","body":"These questions reward careful scanning rather than deep interpretation. The answer is stated directly somewhere in the text; your job is to find it fast.\n\n- Pull a keyword from the question (a name, number, date, or term) and scan for it in the passage.\n- Watch for synonyms. The passage may say \"physician\" where the question says \"doctor.\"\n- Confirm the surrounding sentence actually answers the question before you commit.\n\nDo not rely on memory from your first read. Go back and point to the exact line. The correct answer will match the text precisely, while wrong answers often swap a number or a detail just enough to be false."},{"heading":"Information from a printed communication","body":"Expect everyday documents: emails, memos, letters, notices, flyers, and labels. You will be asked for the sender, recipient, purpose, deadline, required action, or a specific fact.\n\nUse the document's structure as a map. In an email, scan the From, To, Subject, and Date lines first; in a memo or flyer, scan headings, bold text, and any \"RE:\" or \"action required\" lines.\n\nMini-example: A staff memo reads, \"All employees must complete the updated safety training by Friday, March 14. Those who finish early may leave the optional refresher session.\" Question: What is required of all employees? Completing the safety training by March 14. The refresher is optional, so it is a detail, not the required action. Distinguish what is mandatory from what is merely allowed."},{"heading":"Information from a graphic","body":"Graphics include tables, charts, graphs, diagrams, labels, schedules, and maps. Before reading any data, orient yourself: read the title, the axis labels, the units, the legend or key, and any footnotes.\n\n- For tables, find the right row and the right column, then read where they intersect.\n- For line and bar graphs, check what each axis measures and note trends (rising, falling, peak, lowest point).\n- For diagrams and maps, use the labels and key rather than guessing from the picture.\n\nMini-example: A bar graph titled \"Average Daily Patients by Weekday\" shows Monday at 60 and Wednesday at 45. Question: How many more patients on Monday than Wednesday? 60 minus 45 equals 15. Always answer from the labeled values, not from how tall a bar looks at a glance."},{"heading":"Interpreting events in a sequence","body":"Sequence questions ask what happened first, next, or last, or to put steps in correct order. The catch is that authors do not always tell events in chronological order, so you must track the actual timeline, not just the order of sentences.\n\nLean on time-order signal words: \"first,\" \"then,\" \"next,\" \"before,\" \"after,\" \"finally,\" \"meanwhile,\" \"during,\" and dates or times.\n\nMini-example: \"After she submitted her application, Maria scheduled the entrance exam. She had already requested her transcripts the week before.\" Earliest to latest: requested transcripts, submitted application, scheduled the exam. Notice the text mentions the transcripts last but they happened first, which is exactly the kind of reversal the test uses to catch you."},{"heading":"Test-day tips","body":"- Read the question first when it points to a specific fact, then scan the passage with that target in mind.\n- For main-idea and summary questions, beware answers that are true but too narrow or too broad. The right one fits the whole passage exactly.\n- For inferences, pick the choice with the most textual support and reject anything that needs outside knowledge.\n- Circle signal words for directions and sequences: before, after, until, unless, if, do not, first, finally.\n- On graphics, read the title, axes, units, and key before touching the numbers.\n- When two answers seem close, find the word in one of them that the passage does not support, and eliminate it.\n- Manage time: these questions are answerable from the text, so do not overthink. Trust the evidence on the page, not your own assumptions."}]},
  {"section":"READING","topic":"craft-structure","title":"Craft & Structure","intro":"Craft and Structure questions ask you to look past what a passage says and notice how and why it was written. You will judge facts versus opinions, spot bias, figure out word meanings, and recognize an author's purpose, point of view, and the way a text is organized.","sections":[{"heading":"Fact vs. Opinion","body":"A fact can be proven true or false with evidence. An opinion expresses a belief, judgment, or feeling and cannot be proven.\n\nFacts use measurable, checkable language: dates, numbers, names, events. Opinions use judgment words: best, worst, should, beautiful, terrible, probably, I believe.\n\nExamples:\n- Fact: The human heart has four chambers.\n- Fact: Nursing programs in this state require a passing TEAS score.\n- Opinion: Nursing is the most rewarding career anyone can choose.\n- Opinion: The new scrubs are ugly.\n\nHow it appears on the test: You may be asked which sentence states a fact, which states an opinion, or whether a claim is verifiable. Watch for opinions disguised as facts. \"Studies show this is the best treatment\" still contains the judgment word best, so it is an opinion even though it sounds scientific.\n\nQuick tip: Ask yourself, Could two reasonable people check this and agree? If yes, it is likely a fact. If it depends on taste or values, it is an opinion."},{"heading":"Bias and Stereotypes","body":"Bias is a one-sided slant. A biased author favors one position and downplays or ignores other views. Bias is not always wrong, but you should be able to detect it.\n\nClues to bias:\n- Loaded or emotional words (greedy, heroic, disastrous)\n- Only one side of an issue is presented\n- Sweeping claims with no evidence\n- Words like always, never, everyone, no one\n\nA stereotype is an oversimplified belief that all members of a group share a trait. Example: \"Older students struggle with technology.\" That assumes something about an entire group and ignores individuals.\n\nExample of bias: \"Any sensible person knows night-shift nurses are treated unfairly.\" The phrase any sensible person pressures you to agree and shows the author has taken a side.\n\nHow it appears on the test: You may be asked to identify a biased statement, spot a stereotype, or explain how word choice reveals the author leans one way. Look for emotional language and unsupported generalizations."},{"heading":"Word Meaning from Context","body":"Context clues are hints in the surrounding words and sentences that help you define an unfamiliar word or phrase. You do not need a dictionary; the passage gives you what you need.\n\nCommon context clue types:\n- Definition: the word is explained directly. \"She was lethargic, meaning sluggish and lacking energy.\"\n- Synonym: a nearby word means about the same thing. \"He was candid, honest and open about the mistake.\"\n- Antonym or contrast: a nearby word means the opposite, often after but, although, or unlike. \"Unlike his talkative sister, Ben was taciturn.\" Taciturn must mean quiet.\n- Example: nearby examples reveal the meaning. \"Citrus fruits, such as oranges and lemons, are acidic.\"\n\nHow it appears on the test: A word is bolded or quoted and you pick its meaning as used in the passage. Always choose the meaning that fits the sentence, even if a word has several definitions. The phrase \"as used in the passage\" means the right answer depends on context, not on the most common definition."},{"heading":"Dictionary and Library Entries","body":"The test checks whether you can use reference tools correctly.\n\nGuide words: the two words at the top of a dictionary page show the first and last entries on that page. A word belongs on that page only if it falls alphabetically between them. If guide words are marsh and mast, then mask fits but match does not.\n\nDictionary entry parts:\n- The headword (the word being defined) with syllable breaks\n- Pronunciation\n- Part of speech: n. noun, v. verb, adj. adjective, adv. adverb\n- One or more numbered definitions\n- Sometimes the word origin or example sentences\n\nParts of speech matter because one word can be more than one. \"Record\" is a noun (a record) and a verb (to record). Pick the definition that matches how the word works in the sentence.\n\nLibrary entries: a catalog entry lists title, author, call number, publisher, and date. The call number tells you where to find the item on the shelf.\n\nHow it appears on the test: You may be asked which word fits between two guide words, which definition matches a sentence, or which part of speech a word is."},{"heading":"Author's Purpose","body":"The author's purpose is the reason the text was written. The three broad purposes are easy to remember as PIE:\n- Persuade: convince you to think or act a certain way (editorials, ads, opinion columns)\n- Inform: teach or explain facts (textbooks, news reports, manuals)\n- Entertain: tell a story or amuse (novels, personal essays, humor)\n\nSome lists add to express feelings or to describe, but PIE covers the main test cases.\n\nExamples:\n- \"Vote yes to fund the new clinic.\" Purpose is to persuade.\n- \"The clinic opens at 8 a.m. and offers free screenings.\" Purpose is to inform.\n- \"The morning I first walked into that clinic, my hands would not stop shaking.\" Purpose is to entertain or share an experience.\n\nHow it appears on the test: You identify why the author wrote the passage, or why a specific detail or paragraph was included. Match the tone and content to the purpose. Lots of facts and neutral tone signals inform; calls to action and emotional appeals signal persuade."},{"heading":"Text Structure","body":"Text structure is how a passage is organized. Recognizing it helps you predict and locate information. The main patterns and their signal words:\n\n- Cause and effect: explains why something happens and what results. Signals: because, since, therefore, as a result, leads to, due to.\n- Compare and contrast: shows similarities and differences. Signals: similarly, likewise, both, however, unlike, on the other hand, in contrast.\n- Sequence or chronological: events or steps in order. Signals: first, next, then, after, finally, dates, numbered steps.\n- Problem and solution: presents an issue and a way to fix it. Signals: problem, issue, solution, resolve, answer, propose.\n\nExample: \"Because the unit was short-staffed, wait times grew. To solve this, the hospital hired float nurses.\" This blends cause and effect with problem and solution.\n\nHow it appears on the test: You name the structure of a passage or paragraph, or you use the structure to answer a question (for example, putting steps in order). Let the signal words guide you."},{"heading":"Types of Writing","body":"Every passage fits a type. The four common types:\n\n- Narrative: tells a story, real or imagined. Has characters, a setting, and a sequence of events. Often first person (I, we). Example: a nurse recounting her first day.\n- Expository: explains or informs. Presents facts clearly and objectively. Example: an article on how vaccines work.\n- Persuasive: argues a position and tries to convince the reader. Uses reasons, evidence, and sometimes emotion. Example: a letter urging the board to raise nurse pay.\n- Technical: gives precise instructions or specialized information. Includes manuals, procedures, and step-by-step directions. Example: how to operate an IV pump.\n\nHow it appears on the test: You classify the passage by type, or distinguish two types. Watch for overlap. Expository and technical both inform, but technical is hands-on and procedural. Narrative and persuasive can both use emotion, but narrative tells a story while persuasive pushes a viewpoint."},{"heading":"Point of View and Perspective","body":"Point of view is the position from which a text is told. In nonfiction it also means the author's perspective, the attitude or stance toward the topic.\n\nNarrative point of view:\n- First person: narrator is in the story, uses I, me, we. You see only what that narrator knows.\n- Second person: speaks directly to you using you. Common in instructions.\n- Third person: uses he, she, they. The narrator is outside the action. Third-person omniscient knows all characters' thoughts; third-person limited follows one character.\n\nAuthor's perspective: how the writer feels about the subject, shown through word choice and tone. A writer who calls a policy \"a long-overdue reform\" clearly supports it; one who calls it \"a reckless gamble\" opposes it.\n\nHow it appears on the test: You identify the point of view (first vs. third person) or describe the author's attitude. Pronouns reveal narrative point of view. Tone and loaded words reveal perspective. Do not confuse purpose (why they wrote) with perspective (how they feel about it)."},{"heading":"Test-day tips","body":"- Read the question first so you know whether it asks about fact, purpose, structure, or point of view.\n- For fact vs. opinion, hunt for judgment words: best, should, beautiful, probably.\n- For word meaning, always pick the definition that fits the sentence, signaled by the phrase \"as used in the passage.\"\n- For purpose, remember PIE: Persuade, Inform, Entertain.\n- For structure, let signal words point you to the pattern.\n- For point of view, check the pronouns first, then the tone.\n- Spot bias through emotional language and one-sided claims with words like always and never.\n- Eliminate answers that are too extreme or that bring in information the passage never mentions.\n- Stay with what the text actually states; do not add your own knowledge or opinions."}]},
  {"section":"READING","topic":"integration-knowledge","title":"Integration of Knowledge & Ideas","intro":"This skill cluster asks you to do more than locate facts. You will use text to predict and infer, compare ideas across passages, judge how strong an argument is, sort source types, and pull together information from a passage plus a chart or table.","sections":[{"heading":"What this section tests","body":"Integration of Knowledge & Ideas is the highest-thinking part of TEAS Reading. Instead of asking what a sentence says, it asks what the text means, how strong it is, and how two pieces of information fit together.\n\nYou will see five recurring task types:\n\n- Predictions, inferences, and conclusions drawn from evidence\n- Comparing and contrasting themes across one or more texts\n- Evaluating an argument (claims, evidence, reasoning, and flaws)\n- Identifying primary versus secondary sources\n- Combining data from a passage with a table, graph, or label\n\nThe golden rule for all of them: stay anchored to the text. The correct answer is supported by the words on the page, not by your outside opinion or personal experience."},{"heading":"Predictions, inferences, and conclusions","body":"These three are close cousins, and the test treats them as 'reading between the lines.' Each must be backed by evidence in the passage.\n\n- A prediction states what will likely happen next based on clues given.\n- An inference is an unstated idea the author implies but does not say directly.\n- A conclusion pulls several stated details together into one logical takeaway.\n\nHow it appears: questions phrased as 'Which prediction is best supported,' 'It can be inferred that,' or 'The passage suggests that.'\n\nExample: A passage reads, 'Maria checked the supply cart, found the gauze bin empty again, and sighed as she wrote a third note to the manager.' \n- Inference: the gauze runs out often (the word 'again' and 'third note' imply a repeated problem). \n- Prediction: Maria will likely report the shortage or restock it herself. \n- Conclusion: the unit has an ongoing supply-tracking problem.\n\nTrap to avoid: an answer can be true in real life but still wrong if the passage does not support it. Pick the choice you can point to evidence for."},{"heading":"Compare and contrast themes across texts","body":"A theme is the central message or lesson, not just the topic. The topic might be 'vaccination'; the theme might be 'public health depends on individual choices.'\n\nHow it appears: you get one passage with two ideas, or two short passages side by side, and you are asked how their themes, tones, or viewpoints are alike or different.\n\nSteps that work:\n\n- State each text's theme in your own short phrase.\n- Ask what they share (the compare) and where they split (the contrast).\n- Watch the tone: one author may be hopeful, another cautious, even on the same subject.\n\nExample: Passage A argues that night-shift naps boost nurse alertness and patient safety. Passage B argues that scheduled naps disrupt workflow and hand-offs. \n- Shared theme: both care about nurse performance and patient safety. \n- Contrast: A frames rest as the solution; B frames it as a risk to coordination.\n\nThe right answer usually names both the common ground and the precise point of disagreement, not just one side."},{"heading":"Evaluate an argument","body":"An argument has parts, and the test wants you to take it apart.\n\n- Claim: the main point the author wants you to accept.\n- Evidence: facts, data, examples, or expert statements offered as support.\n- Reasoning: the logic connecting the evidence to the claim.\n- Flaw: a weakness, such as a missing piece, an overreach, or a biased source.\n\nHow it appears: 'Which statement is the author's main claim,' 'Which detail best supports the claim,' 'Which weakens the argument,' or 'What is a flaw in the reasoning.'\n\nExample: 'Our clinic should drop paper charts. Since switching three rooms to tablets last month, those rooms had fewer charting errors. Going fully digital will eliminate errors.' \n- Claim: the clinic should go fully digital. \n- Evidence: three rooms had fewer errors after switching. \n- Flaw: one month and three rooms is a small sample, and 'eliminate' overstates 'fewer.' Correlation is treated as proof.\n\nTo strengthen an argument, look for added relevant evidence. To weaken it, look for a counterexample or an exposed gap."},{"heading":"Primary vs secondary sources","body":"This is a quick classification skill, and it is easy points once the definitions are clear.\n\n- A primary source is firsthand and original: the direct record created by someone with direct experience. Examples: a nurse's own shift notes, a patient's diary, raw lab results, an original research study reporting its own data, an interview transcript, a photograph, a historical letter.\n- A secondary source describes, analyzes, or summarizes primary material after the fact. Examples: a textbook chapter, a magazine article about a study, a literature review, an encyclopedia entry, a news report summarizing research.\n\nHow it appears: 'Which of these is a primary source,' or a scenario where you must label one document.\n\nQuick test: Ask, 'Was this made by someone who was directly there or who generated the original data?' If yes, primary. If it is someone reviewing or retelling that work, secondary.\n\nExample: The original study where researchers measured blood pressure in 200 patients is primary. A blog post explaining that study to the public is secondary."},{"heading":"Integrate data from multiple sources","body":"Here a passage is paired with a table, graph, chart, nutrition label, schedule, or diagram, and you must use both together.\n\nHow it appears: the question cannot be answered from the text alone or the graphic alone. You must match a statement in the passage to a number or trend in the visual, or spot where they agree or conflict.\n\nA reliable routine:\n\n- Read the title, axis labels, units, and any legend or footnote first. Misreading units (mg vs g, percent vs count) is the top error.\n- Find the specific row, bar, or data point the question names.\n- Connect it back to the passage claim and confirm they line up.\n\nExample: A passage says, 'Hydration stations cut reported headaches the most in the afternoon.' A bar graph shows headache reports by time of day. The correct reading is the afternoon bar showing the largest drop. If the passage and the graph disagree, the question may be testing whether you notice the mismatch, so read carefully rather than assuming they match.\n\nTreat the graphic as part of the text, not decoration."},{"heading":"How to attack these questions","body":"A repeatable approach keeps you anchored and fast.\n\n- Identify the task type first: predict, infer, compare, evaluate, classify, or integrate. The wording tells you which tool to use.\n- Go back to the passage or graphic before reading the answer choices. Decide what you expect, then match.\n- For every inference or conclusion, silently name the line that supports it. No support means wrong choice.\n- Eliminate choices that are too extreme ('always,' 'never,' 'proves,' 'eliminates') unless the text truly says so.\n- Eliminate choices that are true in the world but absent from the passage.\n- For data questions, double-check units and which row or bar is referenced.\n\nThe most common wrong answers are the ones that sound smart but go beyond what the text provides."},{"heading":"Test-day tips","body":"- Read the question stem first so you know which skill is being tested before you dive in.\n- Underline or mentally mark each claim and its evidence as you read an argument passage.\n- For inferences, choose the smallest reasonable step beyond the text, not the biggest leap.\n- When comparing texts, summarize each theme in three or four words before answering.\n- Primary equals firsthand and original; secondary equals retold or analyzed. Repeat it if you blank.\n- Always check graphic titles, units, and legends before trusting a number.\n- If two answers seem close, pick the one with clearer textual support and less overreach.\n- Watch for absolute words; they often signal an overstated, incorrect choice.\n- Manage your time: these items reward a quick second look at the text more than long deliberation."}]},
  {"section":"MATH","topic":"numbers-algebra","title":"Numbers & Algebra","intro":"This lesson rebuilds the core arithmetic and algebra you need for the TEAS, one skill at a time, with every step shown. Work through each example with a pencil so the methods become automatic.","sections":[{"heading":"Arithmetic with rational numbers","body":"A rational number is any number you can write as a fraction: whole numbers, decimals, and fractions all count. Here are the four operations.\n\nADD/SUBTRACT DECIMALS: line up the decimal points, then add or subtract column by column.\n- Example: 12.4 + 3.75. Line up: 12.40 + 3.75. Add: 16.15.\n- Example: 8.2 − 5.67. Write 8.20 − 5.67 = 2.53.\n\nMULTIPLY DECIMALS: ignore the points, multiply as whole numbers, then count total decimal places and place the point.\n- Example: 1.2 × 0.05. Do 12 × 5 = 60. Decimal places: 1 + 2 = 3. So 0.060 = 0.06.\n\nDIVIDE DECIMALS: move the divisor's point to make it a whole number, move the dividend's point the same amount.\n- Example: 4.5 ÷ 0.9. Move both one place: 45 ÷ 9 = 5.\n\nADD/SUBTRACT FRACTIONS need a COMMON DENOMINATOR (a number both denominators divide into).\n- Example: 1/4 + 2/3. The least common denominator of 4 and 3 is 12. Rewrite: 1/4 = 3/12, 2/3 = 8/12. Add: 3/12 + 8/12 = 11/12.\n- Example: 5/6 − 1/4. LCD of 6 and 4 is 12. 5/6 = 10/12, 1/4 = 3/12. Subtract: 10/12 − 3/12 = 7/12.\n\nMULTIPLY FRACTIONS: multiply tops, multiply bottoms, simplify. No common denominator needed.\n- Example: 2/3 × 3/5 = (2×3)/(3×5) = 6/15 = 2/5.\n\nDIVIDE FRACTIONS: keep the first, flip the second, multiply (keep-change-flip).\n- Example: 3/4 ÷ 2/5 = 3/4 × 5/2 = 15/8 = 1 7/8."},{"heading":"Convert among decimals, fractions, and percents","body":"These three forms describe the same value, so you must move between them fluently.\n\nFRACTION to DECIMAL: divide the top by the bottom.\n- Example: 3/8 = 3 ÷ 8 = 0.375.\n\nDECIMAL to PERCENT: multiply by 100 (move the point 2 places right) and add %.\n- Example: 0.375 × 100 = 37.5%.\n\nPERCENT to DECIMAL: divide by 100 (move the point 2 places left), drop the %.\n- Example: 8% = 0.08. Example: 125% = 1.25.\n\nDECIMAL to FRACTION: write the digits over the place value, then simplify.\n- Example: 0.45 = 45/100 = 9/20.\n\nFRACTION to PERCENT: convert to a decimal first, then multiply by 100.\n- Example: 1/8 = 0.125 = 12.5%.\n\nPERCENT to FRACTION: put the percent over 100 and simplify.\n- Example: 60% = 60/100 = 3/5.\n\nMemorize these common conversions to save time: 1/2 = 0.5 = 50%, 1/4 = 0.25 = 25%, 3/4 = 0.75 = 75%, 1/5 = 0.2 = 20%, 1/3 = about 0.333 = about 33.3%, 1/10 = 0.1 = 10%."},{"heading":"Percent word problems","body":"Most percent problems fit the pattern: part = percent × whole. Translate 'of' as multiply, 'is' as equals. Always change the percent to a decimal first.\n\nFINDING A PART (percent OF a number):\n- Example: What is 30% of 80? Part = 0.30 × 80 = 24.\n\nFINDING THE PERCENT (what percent IS one number of another):\n- Example: 18 is what percent of 72? Set up 18 = p × 72, so p = 18 ÷ 72 = 0.25 = 25%.\n\nFINDING THE WHOLE:\n- Example: 15 is 25% of what number? 15 = 0.25 × whole, so whole = 15 ÷ 0.25 = 60.\n\nPERCENT INCREASE: add the increase to the original.\n- Example: A $40 item rises 15%. Increase = 0.15 × 40 = 6. New price = 40 + 6 = $46.\n\nPERCENT DECREASE / DISCOUNT: subtract the decrease from the original.\n- Example: A $50 shirt is 20% off. Discount = 0.20 × 50 = 10. Sale price = 50 − 10 = $40.\n- Shortcut: 20% off means you pay 80%, so 0.80 × 50 = $40.\n\nPERCENT CHANGE from old to new:\n- Example: Price went from 25 to 30. Change = 30 − 25 = 5. Percent change = 5 ÷ 25 = 0.20 = 20% increase. (Always divide by the ORIGINAL.)"},{"heading":"Compare and order rational numbers","body":"To compare numbers in mixed forms, convert them all to the same form, usually decimals, then line up the digits.\n\nCOMPARE FRACTIONS by common denominator OR by converting to decimals.\n- Example: Which is larger, 3/5 or 5/8? Decimals: 3/5 = 0.6, 5/8 = 0.625. Since 0.625 > 0.6, 5/8 is larger.\n\nORDER A MIXED LIST from least to greatest:\n- Example: Order 0.7, 3/5, 65%, 1/2. Convert all to decimals: 0.7, 0.6, 0.65, 0.5. Sort: 0.5, 0.6, 0.65, 0.7. Answer in original form: 1/2, 3/5, 65%, 0.7.\n\nNEGATIVE numbers: the further left on the number line, the smaller. With negatives, the bigger the digits, the smaller the value.\n- Example: Order −2, −0.5, −3/4. As decimals: −2, −0.5, −0.75. Least to greatest: −2, −0.75, −0.5.\n\nCOMPARING DECIMALS: add trailing zeros so they have the same length, then compare left to right.\n- Example: 0.4 vs 0.38. Write 0.40 vs 0.38. Since 40 > 38, 0.4 is larger."},{"heading":"Solve one-variable equations","body":"Goal: get the variable alone. Whatever you do to one side, do to the other. Undo operations in reverse order (undo add/subtract first, then multiply/divide).\n\nONE STEP:\n- Example: x + 7 = 12. Subtract 7 from both sides: x = 5.\n- Example: 4x = 28. Divide both sides by 4: x = 7.\n\nTWO STEP:\n- Example: 3x + 5 = 20. Subtract 5: 3x = 15. Divide by 3: x = 5.\n- Check: 3(5) + 5 = 15 + 5 = 20. Correct.\n\nVARIABLE ON BOTH SIDES: collect variables on one side, numbers on the other.\n- Example: 5x − 4 = 2x + 11. Subtract 2x: 3x − 4 = 11. Add 4: 3x = 15. Divide by 3: x = 5.\n\nWITH FRACTIONS or distribution:\n- Example: 2(x − 3) = 10. Distribute: 2x − 6 = 10. Add 6: 2x = 16. Divide by 2: x = 8.\n- Example: x/4 = 9. Multiply both sides by 4: x = 36.\n\nAlways substitute your answer back to confirm it works."},{"heading":"Estimation and rounding","body":"Rounding makes numbers easier to work with and helps you eliminate wrong answer choices fast.\n\nROUNDING RULE: look at the digit just to the RIGHT of the place you are rounding to. If it is 5 or more, round up; if it is 4 or less, round down (keep the digit).\n- Example: Round 3.467 to the nearest tenth. The hundredths digit is 6 (5 or more), so round up: 3.5.\n- Example: Round 1,842 to the nearest hundred. The tens digit is 4 (4 or less), so round down: 1,800.\n\nESTIMATING SUMS/PRODUCTS: round each number first, then compute.\n- Example: Estimate 312 × 19. Round to 300 × 20 = 6,000 (actual is 5,928, so the estimate is close).\n- Example: Estimate 48.7 + 21.2. Round to 49 + 21 = 70.\n\nUSE ESTIMATION TO CHECK: if a problem asks for 9.8 × 4.9 and a choice says 480, estimate 10 × 5 = 50 and reject 480 immediately. The real answer is about 48."},{"heading":"Ratios and rates","body":"A ratio compares two quantities. A rate is a ratio with different units (like miles per hour). A unit rate has a denominator of 1.\n\nWRITING A RATIO: keep the order the words give you. 'For every 3 nurses there are 12 patients' is 3 to 12, written 3:12 or 3/12, which simplifies to 1:4.\n\nUNIT RATE: divide to get the amount per 1 unit.\n- Example: 150 miles in 3 hours. Unit rate = 150 ÷ 3 = 50 miles per hour.\n- Example: $4.50 for 3 pounds. Unit rate = 4.50 ÷ 3 = $1.50 per pound.\n\nBEST BUY using unit rates:\n- Example: 12 oz for $3.00 vs 20 oz for $4.60. First: 3.00 ÷ 12 = $0.25/oz. Second: 4.60 ÷ 20 = $0.23/oz. The 20 oz is cheaper per ounce.\n\nSCALING A RATIO: multiply both parts by the same number.\n- Example: A recipe uses 2 cups flour to 3 cups water. For 6 cups flour, multiply both by 3: 6 cups flour to 9 cups water."},{"heading":"Proportions and cross-multiplying","body":"A proportion sets two ratios equal: a/b = c/d. To solve for an unknown, cross-multiply (a × d = b × c) and then divide.\n\nSETUP RULE: keep the SAME units in the same positions (top matches top, bottom matches bottom).\n- Example: If 4 pens cost $6, how much do 10 pens cost? Set up pens over dollars: 4/6 = 10/x. Cross-multiply: 4x = 60. Divide: x = 15. So 10 pens cost $15.\n\nMEDICATION/DOSAGE style:\n- Example: A drug is 250 mg per 5 mL. How many mL give 400 mg? Set up mg/mL: 250/5 = 400/x. Cross-multiply: 250x = 5 × 400 = 2,000. Divide: x = 2,000 ÷ 250 = 8 mL.\n\nMAP/SCALE style:\n- Example: 2 inches represents 50 miles. How many miles is 5 inches? 2/50 = 5/x. Cross-multiply: 2x = 250. Divide: x = 125 miles.\n\nCheck: the two cross-products should be equal once you plug your answer back in."},{"heading":"Translate phrases into expressions, equations, inequalities","body":"Word problems become solvable once you turn English into math. Learn the keyword translations.\n\nOPERATION KEYWORDS:\n- Addition: sum, plus, more than, increased by, total.\n- Subtraction: difference, minus, less than, decreased by, fewer.\n- Multiplication: product, times, of, twice, double.\n- Division: quotient, per, divided by, ratio.\n- Equals: is, was, results in, gives.\n\nWATCH WORD ORDER for 'less than' and 'more than' (they flip).\n- '5 less than a number' is x − 5, NOT 5 − x.\n- '7 more than twice a number' is 2x + 7.\n\nEXPRESSIONS (no equals sign):\n- 'The sum of a number and 8' = x + 8.\n- 'Three times a number decreased by 4' = 3x − 4.\n\nEQUATIONS (have equals):\n- 'A number increased by 6 is 14' = x + 6 = 14.\n\nINEQUALITY KEYWORDS: 'at least' means ≥, 'at most' means ≤, 'more than' means >, 'less than' means <, 'no more than' means ≤.\n- Example: 'A nurse must work at least 36 hours' = h ≥ 36.\n- Example: 'The cost must be no more than $50' = c ≤ 50.\n- Example: 'Twice a number plus 3 is more than 11' = 2x + 3 > 11."},{"heading":"Test-day tips","body":"- Read what the question actually asks for: the part, the percent, or the whole. Underline it.\n- Convert mixed forms (fractions, decimals, percents) into one common form before comparing or computing.\n- For percent problems, change the percent to a decimal first, then use part = percent × whole.\n- For proportions, label the units and keep top matching top before you cross-multiply.\n- Estimate first to catch answer choices that are wildly off, then compute exactly.\n- Watch the flip words: 'less than' and 'more than' reverse the order when translating.\n- Always do the same operation to both sides of an equation, and plug your answer back in to check.\n- Simplify fractions fully; the correct choice is usually in lowest terms.\n- Manage time: skip and flag a stuck problem, answer easy ones first, and never leave a blank since there is no penalty for guessing."}]},
  {"section":"MATH","topic":"measurement-data","title":"Measurement & Data","intro":"This lesson covers reading data displays, the four basic statistics, how variables relate, core geometry formulas, and unit conversions you will need for the TEAS and for nursing work. Each skill includes a method and a worked example so you can practice the steps.","sections":[{"heading":"Reading tables, charts, and graphs","body":"Data displays organize numbers so you can answer questions quickly. The trick is to slow down and read the labels before you read the numbers.\n\nMethod:\n- Read the title to learn the overall topic.\n- Read each axis label or column header, including the units (dollars, mL, percent).\n- Note the scale: how much does each grid line or tick mark represent?\n- Find the specific row, column, bar, or point the question asks about.\n- For trends, compare points left to right (rising, falling, flat).\n\nDisplay types:\n- Bar graph: compares amounts across categories. Taller bar means larger value.\n- Line graph: shows change over time. A steep line means fast change.\n- Pie chart: shows parts of a whole. All slices add to 100 percent.\n- Table: exact values in rows and columns.\n\nWorked example:\nA bar graph shows patients seen each day: Mon 12, Tue 18, Wed 15, Thu 20, Fri 10. Question: How many more patients were seen on the busiest day than the slowest day?\n- Busiest day is Thursday with 20.\n- Slowest day is Friday with 10.\n- Difference: 20 - 10 = 10 patients.\n\nWatch for trick wording like \"how many more\" (subtract) versus \"total\" (add)."},{"heading":"Statistics: mean, median, mode, range","body":"These four measures summarize a data set. Always arrange the data and count how many values you have first.\n\nMean (average):\n- Add all values, then divide by how many values there are.\n- Example: data 4, 8, 6, 2. Sum = 20. Count = 4. Mean = 20 / 4 = 5.\n\nMedian (middle value):\n- Put the values in order from smallest to largest.\n- If the count is odd, the median is the exact middle number.\n- If the count is even, the median is the mean of the two middle numbers.\n- Example odd: 2, 4, 6, 8, 9. Middle is 6.\n- Example even: 2, 4, 6, 8. Two middle numbers are 4 and 6. Median = (4 + 6) / 2 = 5.\n\nMode (most frequent):\n- The value that appears most often. There can be more than one mode, or none if all values are different.\n- Example: 3, 7, 7, 7, 9, 9. Mode = 7.\n\nRange (spread):\n- Largest value minus smallest value.\n- Example: 3, 7, 7, 9. Range = 9 - 3 = 6.\n\nWhen to use each:\n- Mean: good for evenly spread data; it uses every value.\n- Median: better when there are outliers (extreme values), because it is not pulled by them. Example: incomes or a few very large numbers.\n- Mode: best for categories or finding the most common choice (most common shoe size, most common dosage).\n- Range: quick measure of how spread out the data is."},{"heading":"Relationships between variables","body":"A variable is a quantity that can change. Two variables can be related in predictable ways.\n\nDirect relationship (direct variation):\n- As one variable increases, the other increases too. As one decreases, the other decreases.\n- Example: more hours worked leads to more pay. Faster speed over the same time leads to greater distance.\n\nInverse relationship (inverse variation):\n- As one variable increases, the other decreases.\n- Example: the more workers on a task, the less time it takes. Higher speed for a fixed distance means less travel time.\n\nLinear trend:\n- When plotted, the points form a straight line or nearly straight line.\n- A line rising left to right shows a positive (direct) trend.\n- A line falling left to right shows a negative (inverse) trend.\n- A flat line shows no change.\n\nWorked example:\nA table shows: 1 hour = 50 miles, 2 hours = 100 miles, 3 hours = 150 miles.\n- As hours go up, miles go up, so this is a direct relationship.\n- Each hour adds the same 50 miles, so the trend is linear.\n- Predict 4 hours: 4 x 50 = 200 miles."},{"heading":"Geometry: perimeter and circumference","body":"Perimeter is the total distance around a flat shape. Circumference is the perimeter of a circle.\n\nFormulas:\n- Rectangle perimeter: P = 2 x length + 2 x width, written P = 2L + 2W.\n- Triangle perimeter: add all three sides, P = a + b + c.\n- Circle circumference: C = 2 x pi x radius = 2(pi)r, or C = (pi) x diameter. Use pi approximately 3.14. The radius is half the diameter.\n\nWorked example (rectangle):\nA room is 12 ft long and 9 ft wide.\n- P = 2(12) + 2(9) = 24 + 18 = 42 ft.\n\nWorked example (circle):\nA round table has a radius of 3 ft.\n- C = 2 x 3.14 x 3 = 18.84 ft.\n- If you are given the diameter of 6 ft instead: C = 3.14 x 6 = 18.84 ft (same answer)."},{"heading":"Geometry: area","body":"Area is the amount of flat surface inside a shape, measured in square units (cm squared, written cm2 or cm with a small 2 exponent, ft squared, etc.).\n\nFormulas:\n- Rectangle area: A = length x width = L x W.\n- Triangle area: A = (1/2) x base x height = (1/2)bh. The height is the straight-up distance to the base, not a slanted side.\n- Circle area: A = pi x radius squared = (pi)r^2. Square the radius first, then multiply by pi.\n\nWorked example (rectangle):\nA bandage is 8 cm by 5 cm.\n- A = 8 x 5 = 40 cm2.\n\nWorked example (triangle):\nBase = 10 in, height = 6 in.\n- A = (1/2) x 10 x 6 = (1/2) x 60 = 30 in2.\n\nWorked example (circle):\nRadius = 4 cm.\n- r^2 = 4 x 4 = 16.\n- A = 3.14 x 16 = 50.24 cm2.\n\nRemember: area answers always use square units."},{"heading":"Geometry: surface area and volume","body":"Volume is the space inside a 3-D solid, measured in cubic units (cm cubed written cm3, m3, etc.). Surface area is the total area of all outside faces, measured in square units.\n\nVolume formulas:\n- Box (rectangular prism): V = length x width x height = L x W x H.\n- Cylinder: V = pi x radius squared x height = (pi)r^2 x H. This is the circle area times the height.\n\nSurface area formulas:\n- Box: SA = 2(LW) + 2(LH) + 2(WH). Add the areas of all six faces.\n- Cylinder: SA = 2(pi)r^2 + 2(pi)r x H. Two circle ends plus the wrap-around side.\n\nWorked example (box volume):\nA carton is 4 cm by 3 cm by 2 cm.\n- V = 4 x 3 x 2 = 24 cm3.\n\nWorked example (box surface area):\nSame carton 4 by 3 by 2.\n- 2(4 x 3) = 24; 2(4 x 2) = 16; 2(3 x 2) = 12.\n- SA = 24 + 16 + 12 = 52 cm2.\n\nWorked example (cylinder volume):\nA can has radius 2 cm and height 5 cm.\n- r^2 = 4.\n- V = 3.14 x 4 x 5 = 62.8 cm3.\n\nVolume uses cubic units; surface area uses square units."},{"heading":"Unit conversions within a system","body":"Converting within one system (all metric, or all standard) means multiplying or dividing by a conversion factor. A helpful rule: going from a larger unit to a smaller unit gives a bigger number (multiply); going from smaller to larger gives a smaller number (divide).\n\nMetric is base-10, so you shift the decimal:\n- 1 km = 1000 m, 1 m = 100 cm, 1 cm = 10 mm.\n- 1 kg = 1000 g, 1 g = 1000 mg.\n- 1 L = 1000 mL.\n\nStandard:\n- 1 ft = 12 in, 1 yd = 3 ft, 1 mi = 5280 ft.\n- 1 lb = 16 oz, 1 ton = 2000 lb.\n- 1 gallon = 4 quarts, 1 quart = 2 pints, 1 pint = 2 cups, 1 cup = 8 fl oz.\n\nMethod (use a conversion ratio so units cancel):\n- Write the starting amount.\n- Multiply by a fraction equal to 1 that has the unit you want on top and the unit you have on bottom.\n\nWorked example (metric):\nConvert 2.5 L to mL.\n- 2.5 L x (1000 mL / 1 L) = 2500 mL.\n\nWorked example (standard):\nConvert 3 lb to oz.\n- 3 lb x (16 oz / 1 lb) = 48 oz.\n\nWorked example (smaller to larger):\nConvert 250 cm to m.\n- 250 cm x (1 m / 100 cm) = 2.5 m."},{"heading":"Unit conversions between systems and temperature","body":"To convert between metric and standard, memorize a few bridge factors and set up the ratio so the unwanted unit cancels.\n\nKey bridge factors:\n- Length: 1 in = 2.54 cm.\n- Mass/weight: 1 kg is approximately 2.2 lb.\n- Volume: 1 L is approximately 1.06 qt (and 1 L = 1000 mL).\n\nWorked example (length):\nConvert 10 in to cm.\n- 10 in x (2.54 cm / 1 in) = 25.4 cm.\n\nWorked example (weight):\nA patient weighs 70 kg. Convert to pounds.\n- 70 kg x (2.2 lb / 1 kg) = 154 lb.\n\nTemperature (these are formulas, not simple ratios):\n- Celsius to Fahrenheit: F = (9/5)C + 32.\n- Fahrenheit to Celsius: C = (5/9)(F - 32).\n\nWorked example (C to F):\nConvert 37 C (normal body temperature) to Fahrenheit.\n- F = (9/5)(37) + 32 = (9 x 37 / 5) + 32 = 66.6 + 32 = 98.6 F.\n\nWorked example (F to C):\nConvert 212 F to Celsius.\n- C = (5/9)(212 - 32) = (5/9)(180) = 100 C."},{"heading":"Quick conversion-factor reference","body":"Memorize these for test day.\n\nLength:\n- 1 in = 2.54 cm\n- 1 ft = 12 in\n- 1 yd = 3 ft\n- 1 mi = 5280 ft\n- 1 m = 100 cm, 1 km = 1000 m, 1 cm = 10 mm\n\nMass / weight:\n- 1 kg is approximately 2.2 lb\n- 1 lb = 16 oz\n- 1 kg = 1000 g, 1 g = 1000 mg\n\nVolume:\n- 1 L = 1000 mL\n- 1 L is approximately 1.06 qt\n- 1 gallon = 4 qt, 1 qt = 2 pt, 1 pt = 2 cups, 1 cup = 8 fl oz\n\nTemperature:\n- F = (9/5)C + 32\n- C = (5/9)(F - 32)\n\nGeometry quick list:\n- Rectangle: P = 2L + 2W, A = L x W\n- Triangle: A = (1/2)bh\n- Circle: C = 2(pi)r, A = (pi)r^2, pi approximately 3.14\n- Box: V = L x W x H\n- Cylinder: V = (pi)r^2 x H"},{"heading":"Test-day tips","body":"- Read the question twice and underline what is actually asked (more than, total, average, convert).\n- Always check units. Area answers are square units, volume answers are cubic units. If your units do not match the answer choices, you missed a conversion.\n- Set up conversions as fractions so unwanted units cancel. This prevents multiplying when you should divide.\n- For mean, add then divide. For median, put numbers in order first, then find the middle.\n- Use pi approximately 3.14 unless the problem says otherwise.\n- For circles, find the radius first; radius = diameter / 2. Square the radius before multiplying for area.\n- Memorize the body-temperature check: 37 C = 98.6 F. It confirms your temperature formula is set up correctly.\n- Estimate before you compute. A rough answer helps you spot a wrong choice.\n- Manage time: do quick reading-the-graph and conversion questions first, then return to multi-step geometry."}]},
  {"section":"SCIENCE","topic":"anatomy-physiology","title":"Human Anatomy & Physiology","intro":"Anatomy and physiology is the largest science sub-area on the TEAS, so a clear mental map of each body system pays off. This lesson gives each system's main job, its key structures, and the high-yield facts you are most likely to be tested on.","sections":[{"heading":"Directional terms, planes, and cavities","body":"All anatomy is described from anatomical position: standing upright, face forward, arms at the sides, palms facing forward.\n\nPaired directional terms (assume anatomical position):\n- Superior (above) vs inferior (below): the head is superior to the chest.\n- Anterior/ventral (front) vs posterior/dorsal (back): the sternum is anterior to the spine.\n- Medial (toward midline) vs lateral (away from midline): the nose is medial to the eyes.\n- Proximal (closer to trunk/point of origin) vs distal (farther away): the elbow is proximal to the wrist.\n- Superficial (toward surface) vs deep (away from surface).\n\nBody planes:\n- Sagittal plane: divides into left and right (midsagittal splits into equal halves).\n- Frontal/coronal plane: divides into anterior and posterior.\n- Transverse/horizontal plane: divides into superior and inferior (cross section).\n\nBody cavities:\n- Dorsal cavity contains the cranial cavity (brain) and vertebral/spinal cavity (spinal cord).\n- Ventral cavity contains the thoracic cavity (heart, lungs) and the abdominopelvic cavity. The diaphragm separates the thoracic from the abdominopelvic cavity."},{"heading":"Integumentary system","body":"Main job: the body's outer covering, the largest organ. It provides protection, prevents water loss, regulates temperature, houses sensory receptors, and synthesizes vitamin D.\n\nKey structures:\n- Epidermis: outer avascular layer, mostly keratinocytes; contains melanocytes that produce melanin (pigment and UV protection).\n- Dermis: deeper layer with blood vessels, nerves, hair follicles, sweat and sebaceous (oil) glands, and collagen for strength.\n- Hypodermis/subcutaneous layer: fat for insulation and cushioning (technically deep to the skin).\n\nHigh-yield facts:\n- Thermoregulation works two ways: sweating cools the body by evaporation, and blood vessels dilate (vasodilation) to release heat or constrict (vasoconstriction) to conserve it.\n- Skin is the first line of nonspecific (innate) defense against pathogens."},{"heading":"Skeletal system","body":"Main job: supports and shapes the body, protects organs, allows movement (with muscles), stores minerals (calcium and phosphorus), and produces blood cells.\n\nKey structures:\n- 206 bones in the adult skeleton, divided into the axial skeleton (skull, vertebral column, rib cage) and the appendicular skeleton (limbs, shoulder and pelvic girdles).\n- Red bone marrow performs hematopoiesis (formation of red blood cells, white blood cells, and platelets).\n- Joints are where bones meet; cartilage cushions and ligaments connect bone to bone.\n\nHigh-yield facts:\n- Bone is living tissue that constantly remodels: osteoblasts build bone and osteoclasts break it down.\n- The skeleton stores about 99 percent of the body's calcium, important for muscle contraction and nerve signaling."},{"heading":"Neuromuscular system (nervous and muscular)","body":"Main job: the nervous system senses, integrates, and commands; the muscular system carries out movement. Together they produce coordinated motion and reflexes.\n\nNervous system structures:\n- Central nervous system (CNS): brain and spinal cord.\n- Peripheral nervous system (PNS): nerves outside the CNS, including the autonomic division (sympathetic 'fight or flight' and parasympathetic 'rest and digest').\n- The neuron is the functional cell; signals travel as electrical impulses and cross synapses via neurotransmitters (for example, acetylcholine).\n\nMuscular system structures and facts:\n- Three muscle types: skeletal (voluntary, striated, attached by tendons), cardiac (involuntary, striated, heart only), and smooth (involuntary, in organ and vessel walls).\n- A reflex arc allows a rapid response that is processed at the spinal cord without waiting for the brain.\n- Muscles can only pull, not push, so they often work in antagonistic pairs (for example, biceps flex and triceps extend the elbow)."},{"heading":"Cardiovascular system and blood-flow path","body":"Main job: the heart pumps blood through vessels to deliver oxygen and nutrients and remove carbon dioxide and wastes.\n\nKey structures:\n- Four chambers: two atria (receiving) on top and two ventricles (pumping) on the bottom.\n- Valves keep blood moving one way: tricuspid (right AV), pulmonary (semilunar), mitral/bicuspid (left AV), and aortic (semilunar).\n- Vessels: arteries carry blood away from the heart, veins return blood to the heart, and capillaries are the site of gas and nutrient exchange.\n\nBlood-flow path (memorize this sequence):\n- Body (deoxygenated blood) into superior and inferior vena cava\n- into right atrium, through tricuspid valve into right ventricle\n- through pulmonary valve into pulmonary arteries to the lungs (picks up oxygen, drops off carbon dioxide)\n- back via pulmonary veins into left atrium, through mitral valve into left ventricle\n- through aortic valve into the aorta and out to the body.\n\nHigh-yield facts:\n- The left ventricle has the thickest wall because it pumps blood to the entire body.\n- Pulmonary arteries carry deoxygenated blood and pulmonary veins carry oxygenated blood, the opposite of the usual artery/vein rule."},{"heading":"Respiratory system","body":"Main job: brings oxygen into the blood and removes carbon dioxide through gas exchange.\n\nKey structures (path of air):\n- Nose/nasal cavity, pharynx, larynx (voice box, contains the epiglottis that covers the trachea during swallowing), trachea, bronchi, bronchioles, and alveoli.\n- Alveoli are tiny air sacs surrounded by capillaries; this is where gas exchange happens by diffusion.\n- The diaphragm is the main muscle of breathing.\n\nHigh-yield facts:\n- Inhalation is active: the diaphragm contracts and flattens, increasing chest volume and lowering pressure so air flows in. Exhalation is usually passive as the diaphragm relaxes.\n- Oxygen moves from alveoli into blood and carbon dioxide moves from blood into alveoli, each diffusing from higher to lower concentration."},{"heading":"Gastrointestinal (digestive) system","body":"Main job: breaks food into absorbable nutrients, absorbs them into the blood, and eliminates solid waste.\n\nKey structures (path of food):\n- Mouth (mechanical chewing plus salivary amylase begins starch digestion), pharynx, esophagus, stomach (acid and pepsin digest protein), small intestine, large intestine, rectum, anus.\n- Accessory organs: liver (produces bile), gallbladder (stores bile), and pancreas (digestive enzymes and bicarbonate).\n\nHigh-yield facts:\n- Most nutrient absorption occurs in the small intestine, whose villi and microvilli hugely increase surface area.\n- The large intestine mainly absorbs water and electrolytes and forms feces.\n- Chemical digestion of starch begins in the mouth, while protein digestion begins in the stomach."},{"heading":"Genitourinary / urinary system and urine path","body":"Main job: filters blood to remove nitrogenous wastes (urea), and regulates water, electrolytes, pH, and blood pressure.\n\nKey structures:\n- Kidneys: filter blood and form urine; the nephron is the functional filtering unit.\n- Ureters, urinary bladder (stores urine), and urethra (carries urine out).\n\nUrine path (memorize this sequence):\n- Blood filtered in the kidney's nephrons\n- urine flows into the renal pelvis\n- down the ureters\n- into the urinary bladder (storage)\n- out through the urethra.\n\nHigh-yield facts:\n- The nephron filters at the glomerulus, then reabsorbs needed water and solutes and secretes wastes along the tubule.\n- The kidneys help regulate blood pressure (via renin) and produce erythropoietin, which stimulates red blood cell production."},{"heading":"Endocrine system (gland to hormone pairs)","body":"Main job: uses hormones released into the bloodstream to regulate slow, widespread processes such as metabolism, growth, and reproduction. It is slower but longer-lasting than nervous control.\n\nKey gland to hormone pairs:\n- Hypothalamus: links the nervous and endocrine systems and controls the pituitary.\n- Pituitary (the 'master gland'): growth hormone, ADH (antidiuretic hormone), oxytocin, and hormones that direct other glands.\n- Thyroid: thyroxine (T4) and T3, which raise metabolic rate; also calcitonin, which lowers blood calcium.\n- Parathyroid: parathyroid hormone (PTH), which raises blood calcium.\n- Adrenal glands: cortisol (stress and glucose) and aldosterone from the cortex; epinephrine and norepinephrine (adrenaline) from the medulla.\n- Pancreas: insulin (lowers blood glucose) and glucagon (raises blood glucose) from the islets.\n- Ovaries: estrogen and progesterone. Testes: testosterone.\n\nHigh-yield facts:\n- Insulin and glucagon are antagonists that keep blood sugar balanced; insulin lowers it, glucagon raises it.\n- Many hormones are controlled by negative feedback, in which the output shuts off further release."},{"heading":"Reproductive system","body":"Main job: produces gametes (sex cells) and sex hormones, and enables fertilization and, in females, pregnancy.\n\nMale structures: testes (produce sperm and testosterone), epididymis (sperm maturation and storage), vas deferens, urethra, and penis. Sperm path: testes, epididymis, vas deferens, urethra.\n\nFemale structures: ovaries (produce eggs and estrogen/progesterone), fallopian tubes (uterine tubes, the usual site of fertilization), uterus (where a fertilized egg implants and develops), and vagina.\n\nHigh-yield facts:\n- Fertilization typically occurs in the fallopian tube; implantation occurs in the uterus.\n- Gametes are produced by meiosis and are haploid (23 chromosomes); fertilization restores the diploid number (46)."},{"heading":"Immune (lymphatic) system","body":"Main job: defends against pathogens, removes damaged cells, and (via the lymphatic vessels) returns excess tissue fluid to the blood.\n\nKey structures:\n- Lymph nodes (filter lymph and trap pathogens), spleen, thymus (where T cells mature), tonsils, and lymphatic vessels.\n- White blood cells (leukocytes), including lymphocytes (B cells and T cells), are the main defenders.\n\nHigh-yield facts:\n- Innate (nonspecific) immunity is the rapid first response (skin, inflammation, phagocytes); adaptive (specific) immunity is slower and targets specific antigens with memory.\n- B cells produce antibodies (humoral immunity); T cells drive cell-mediated immunity. Memory cells provide long-term immunity, which is the basis of vaccination."},{"heading":"Test-day tips","body":"- Learn the two ordered sequences cold: the cardiac blood-flow path and the urine path. These show up as fill-in-order or 'what comes next' questions.\n- For directional terms, always reset to anatomical position before answering, and watch for the pairs (the wrist is distal to the elbow, the heart is medial to the lung).\n- Remember the pulmonary exception: pulmonary arteries carry deoxygenated blood, pulmonary veins carry oxygenated blood.\n- Match glands to hormones using antagonistic pairs you can reason about: insulin lowers and glucagon raises blood glucose; calcitonin lowers and PTH raises blood calcium.\n- Know where digestion of each nutrient begins: carbohydrates in the mouth, protein in the stomach, and most absorption in the small intestine.\n- Distinguish innate vs adaptive immunity and B cells (antibodies) vs T cells (cell-mediated).\n- Read carefully for 'superior/inferior' and 'anterior/posterior' swaps in answer choices, a common trick. Eliminate obviously reversed options first."}]},
  {"section":"SCIENCE","topic":"biology","title":"Biology","intro":"Biology questions on the TEAS focus on the cell, how genetic information becomes protein, basic inheritance, the building-block molecules of life, and how microbes cause disease. This lesson walks through each skill with plain explanations and quick examples.","sections":[{"heading":"Cell structure, function, and organization","body":"The cell is the basic unit of life. There are two broad cell types.\n\n- Prokaryotic cells (bacteria, archaea): no true nucleus and no membrane-bound organelles; DNA floats in the cytoplasm in a region called the nucleoid; small and simple.\n- Eukaryotic cells (animals, plants, fungi, protists): have a true membrane-bound nucleus and membrane-bound organelles; larger and more complex.\n\nKey organelles and their jobs:\n\n- Nucleus: stores DNA and directs cell activities.\n- Mitochondria: make ATP (energy) through cellular respiration; the powerhouse of the cell.\n- Ribosomes: build proteins; found free in cytoplasm or on rough ER.\n- Rough endoplasmic reticulum (ER): studded with ribosomes; processes and folds proteins.\n- Smooth ER: makes lipids and helps detoxify.\n- Golgi apparatus: packages, modifies, and ships proteins and lipids.\n- Lysosomes: contain enzymes that digest waste and worn-out parts.\n- Cell (plasma) membrane: a phospholipid bilayer that controls what enters and leaves.\n- Plant-only extras: cell wall (support), chloroplasts (photosynthesis), large central vacuole (storage).\n\nLevels of organization, smallest to largest: cells form tissues, tissues form organs, organs form organ systems, and organ systems form the whole organism. Example: cardiac muscle cells make heart tissue, which forms the heart (organ), part of the cardiovascular system, within the body."},{"heading":"Genetic material and protein structure (DNA to RNA to protein)","body":"Genetic information flows in one main direction, called the central dogma: DNA to RNA to protein.\n\nDNA is a double helix made of nucleotides. Each nucleotide has a sugar (deoxyribose), a phosphate, and one of four bases: A, T, C, G. Bases pair A-T and C-G. RNA is single-stranded, uses the sugar ribose, and replaces thymine (T) with uracil (U), so it pairs A-U and C-G.\n\nTwo key steps:\n\n- Transcription (in the nucleus): one DNA strand is used as a template to build a complementary messenger RNA (mRNA) strand. Example: DNA template A-T-G-C becomes mRNA U-A-C-G.\n- Translation (at the ribosome): the ribosome reads the mRNA three bases at a time. Each three-base unit is a codon, and each codon specifies one amino acid. Transfer RNA (tRNA) brings the matching amino acids, which link into a protein chain.\n\nExample: the mRNA codon AUG codes for the amino acid methionine and also acts as the start codon. Stop codons (UAA, UAG, UGA) signal the end of the chain. There are 64 possible codons coding for 20 amino acids, so more than one codon can specify the same amino acid."},{"heading":"Mendelian inheritance","body":"Genes come in versions called alleles. You inherit one allele from each parent.\n\n- Dominant allele: shown with a capital letter (B); its trait appears even if only one copy is present.\n- Recessive allele: shown with a lowercase letter (b); its trait appears only when two copies are present.\n- Genotype: the actual alleles (BB, Bb, or bb). Homozygous means two of the same (BB or bb); heterozygous means two different (Bb).\n- Phenotype: the physical trait you can observe (for example, brown vs. blue eyes).\n\nA Punnett square predicts offspring. Place one parent's alleles across the top and the other parent's down the side, then fill each box."},{"heading":"Worked Punnett-square example","body":"Cross two heterozygous brown-eyed parents: Bb x Bb. B (brown) is dominant, b (blue) is recessive.\n\nSet up the square with B and b on each axis:\n\n-        B        b\n- B     BB      Bb\n- b     Bb      bb\n\nResults (the four boxes):\n\n- 1 BB, 2 Bb, 1 bb\n\nGenotype ratio: 1 BB : 2 Bb : 1 bb.\n\nPhenotype ratio: 3 brown eyes : 1 blue eyes, because BB, Bb, and Bb all show brown (dominant), and only bb shows blue. That is a 3:1 ratio, or a 75% chance of brown and 25% chance of blue per child."},{"heading":"Macromolecules","body":"Four classes of large biological molecules are built from smaller repeating units called monomers.\n\n- Carbohydrates: monomer is the monosaccharide (simple sugar like glucose). Function: quick energy and short-term storage; structural support in plants (cellulose). Example: starch, glycogen.\n- Lipids (fats, oils, phospholipids, steroids): not built from a single repeating monomer, but include fatty acids and glycerol. Function: long-term energy storage, insulation, and forming cell membranes (phospholipid bilayer). Cholesterol is a steroid lipid.\n- Proteins: monomer is the amino acid (20 types). Function: enzymes (speed up reactions), structure, transport, defense (antibodies), and muscle movement.\n- Nucleic acids (DNA and RNA): monomer is the nucleotide. Function: store and transmit genetic information.\n\nA memory hook: carbohydrates and lipids power and protect you, proteins do the work, and nucleic acids carry the instructions."},{"heading":"Microorganisms in disease","body":"Microorganisms (microbes) are organisms too small to see without a microscope. Several types cause illness.\n\n- Bacteria: single-celled prokaryotes. Many are harmless or helpful, but pathogenic ones cause disease by multiplying and releasing toxins. Examples: strep throat, tuberculosis, urinary tract infections. Treated with antibiotics.\n- Viruses: not cells and not technically alive on their own. A virus is genetic material (DNA or RNA) in a protein coat. It must invade a host cell and hijack its machinery to copy itself, often destroying the cell. Examples: influenza, the common cold, COVID-19, HIV. Antibiotics do not work on viruses; some are treated with antivirals or prevented with vaccines.\n- Fungi: eukaryotes such as yeasts and molds. They cause infections especially on skin or in immunocompromised people. Examples: athlete's foot, ringworm, yeast infections. Treated with antifungals.\n- Protozoa and parasites: single-celled eukaryotes (like the one causing malaria) can also cause disease.\n\nKey contrast: bacteria are living cells you can treat with antibiotics; viruses are non-cellular and need a host, so they require different treatment."},{"heading":"Test-day tips","body":"- Memorize organelle jobs as one-liners: mitochondria make energy, ribosomes make protein, nucleus holds DNA.\n- Remember prokaryote means no nucleus; eukaryote means true nucleus.\n- For DNA vs. RNA: DNA is double-stranded with thymine; RNA is single-stranded with uracil.\n- Reading frame: codon equals 3 bases equals 1 amino acid; AUG is start.\n- Capital letter equals dominant, lowercase equals recessive. For a Bb x Bb cross, expect a 3:1 phenotype ratio and 1:2:1 genotype ratio.\n- Match each macromolecule to its monomer: carbohydrate-monosaccharide, protein-amino acid, nucleic acid-nucleotide; lipids are the odd one out (no single monomer).\n- Antibiotics treat bacteria, not viruses. If a question pairs a virus with antibiotics, that answer is wrong.\n- Watch for the levels-of-organization order: cell, tissue, organ, organ system, organism."}]},
  {"section":"SCIENCE","topic":"chemistry","title":"Chemistry","intro":"Chemistry explains what matter is made of and how it changes. This lesson covers atomic structure, physical versus chemical changes, chemical reactions, and the properties of solutions including acids and bases.","sections":[{"heading":"Atomic structure","body":"Every atom has a central nucleus surrounded by electrons. The nucleus contains protons and neutrons, which hold nearly all of the atom's mass.\n\n- Protons: positive charge (+1), located in the nucleus\n- Neutrons: no charge (neutral), located in the nucleus\n- Electrons: negative charge (-1), located in the electron cloud or orbitals around the nucleus\n\nA neutral atom has an equal number of protons and electrons, so the charges cancel out. Electrons are far smaller and lighter than protons and neutrons, so they add almost no mass.\n\nProtons and neutrons each weigh about 1 atomic mass unit. An electron weighs roughly 1/1836 of that, which is why electron mass is usually ignored when finding mass."},{"heading":"Atomic number, mass number, and ions","body":"The atomic number is the number of protons in an atom. It defines the element and never changes for that element. For example, every carbon atom has 6 protons, so carbon's atomic number is 6.\n\nThe mass number is the total number of protons plus neutrons in the nucleus. Electrons are not counted because their mass is negligible.\n\n- Number of neutrons = mass number - atomic number\n- Example: an atom with mass number 23 and atomic number 11 (sodium) has 23 - 11 = 12 neutrons\n\nWhen an atom gains or loses electrons it becomes an ion. Losing electrons leaves more protons than electrons, giving a positive charge (a cation). Gaining electrons gives a negative charge (an anion). Gaining or losing electrons does not change which element it is."},{"heading":"Isotopes","body":"Isotopes are atoms of the same element that have the same number of protons but different numbers of neutrons. Because the proton count is unchanged, they are still the same element, but their mass numbers differ.\n\n- Carbon-12 has 6 protons and 6 neutrons\n- Carbon-14 has 6 protons and 8 neutrons\n\nBoth are carbon (atomic number 6), but carbon-14 is heavier and is unstable, which makes it radioactive. The atomic mass shown on the periodic table is a weighted average of all an element's naturally occurring isotopes, which is why it is usually a decimal."},{"heading":"States of matter and physical changes","body":"Matter commonly exists in three states. The particles are the same substance in each state; only their arrangement and energy differ.\n\n- Solid: fixed shape and volume, particles packed tightly\n- Liquid: fixed volume but takes the shape of its container, particles flow past each other\n- Gas: no fixed shape or volume, particles spread out and move freely\n\nA physical change alters the form or appearance of matter without creating a new substance. The chemical identity stays the same and the change is often reversible. Examples include changing state, dissolving sugar in water, cutting paper, or crushing a can.\n\nChanges of state by name:\n- Melting: solid to liquid\n- Freezing: liquid to solid\n- Boiling or vaporization: liquid to gas\n- Condensation: gas to liquid\n- Sublimation: solid directly to gas (for example, dry ice or CO2)\n- Deposition: gas directly to solid"},{"heading":"Chemical changes","body":"A chemical change (chemical reaction) produces one or more new substances with new properties. The original substances are used up and rearranged into different ones, and the change is usually not easily reversible.\n\nSigns that a chemical change has occurred:\n- Color change\n- Gas bubbles or odor produced\n- A solid (precipitate) forming from liquids\n- Heat, light, or temperature change\n- Hard to reverse\n\nExamples include burning wood, rusting iron, baking a cake, and digesting food. Compare this to a physical change like boiling water, which is still water as gas. Burning that wood creates ash and gases, which are new substances, so it is chemical."},{"heading":"Chemical reactions, conservation of mass, and balancing","body":"In a chemical equation, the starting substances are reactants (left of the arrow) and the substances formed are products (right of the arrow). The arrow means yields.\n\nThe law of conservation of mass states that matter is not created or destroyed in a reaction. Every atom on the reactant side must appear on the product side, so the total mass stays the same. This is why equations must be balanced.\n\nTo balance, adjust the coefficients (the big numbers in front) so each element has equal atom counts on both sides. Never change subscripts, because that changes the substance.\n\nBalanced example (formation of water):\n2 H2 + O2 -> 2 H2O\n\nCheck the atoms: left side has 4 hydrogen and 2 oxygen; right side has 4 hydrogen (2 x 2) and 2 oxygen. Both sides match, so mass is conserved."},{"heading":"Types of reactions","body":"Most reactions fit into a few common patterns. Recognizing them helps you predict products.\n\n- Synthesis (combination): two or more simple substances join into one. A + B -> AB. Example: 2 H2 + O2 -> 2 H2O\n- Decomposition: one compound breaks into simpler substances. AB -> A + B. Example: 2 H2O -> 2 H2 + O2\n- Single replacement: one element takes the place of another in a compound. A + BC -> AC + B. Example: Zn + 2 HCl -> ZnCl2 + H2\n- Double replacement: two compounds swap partners. AB + CD -> AD + CB. Example: AgNO3 + NaCl -> AgCl + NaNO3\n- Combustion: a fuel reacts with oxygen, releasing heat and light, usually producing CO2 and H2O. Example: CH4 + 2 O2 -> CO2 + 2 H2O"},{"heading":"Solutions, concentration, and solubility","body":"A solution is a uniform mixture of two or more substances. The solute is the substance being dissolved (present in the smaller amount), and the solvent is the substance doing the dissolving (present in the larger amount). In salt water, salt is the solute and water is the solvent. Water dissolves so many substances it is called the universal solvent.\n\nConcentration describes how much solute is dissolved in a given amount of solvent or solution. A solution with a lot of solute is concentrated; one with little solute is dilute.\n\n- Dilute: small amount of solute\n- Concentrated: large amount of solute\n- Saturated: holds the maximum solute it can at that temperature\n\nSolubility is the maximum amount of a solute that dissolves in a solvent at a given temperature. For most solids in water, solubility increases as temperature rises, and stirring or breaking solids into smaller pieces speeds dissolving. For gases in water, solubility decreases as temperature rises."},{"heading":"Acids, bases, and the pH scale","body":"Acids and bases are special solutions measured by the pH scale, which runs from 0 to 14.\n\n- pH less than 7: acidic (more hydrogen ions, H+). Examples: lemon juice, stomach acid, vinegar\n- pH equal to 7: neutral. Example: pure water\n- pH greater than 7: basic or alkaline (more hydroxide ions, OH-). Examples: baking soda, ammonia, bleach\n\nThe scale is logarithmic, so each whole number step is a tenfold change in acidity. A pH of 4 is ten times more acidic than a pH of 5 and one hundred times more acidic than a pH of 6.\n\nProperties: acids taste sour and react with metals; bases taste bitter and feel slippery. When an acid and a base are mixed, they neutralize each other to form water and a salt, moving the pH toward 7. Blood is kept near a slightly basic pH of about 7.4."},{"heading":"Test-day tips","body":"- Protons set the element and atomic number; neutrons change isotopes and mass; electrons set charge.\n- Neutrons = mass number minus atomic number.\n- Physical change = same substance (state changes, dissolving); chemical change = new substance (color, gas, precipitate, heat).\n- Balance equations by changing coefficients only, never subscripts, and confirm conservation of mass by counting atoms on both sides.\n- Memorize the five reaction types by their patterns; combustion always uses O2 and typically yields CO2 and H2O.\n- Solute dissolves into the solvent; the solvent is the larger amount.\n- pH below 7 is acid, 7 is neutral, above 7 is base; each step is a tenfold change.\n- Read carefully for words like dilute, concentrated, and saturated, and watch the direction of the pH scale."}]},
  {"section":"SCIENCE","topic":"scientific-reasoning","title":"Scientific Reasoning","intro":"Scientific Reasoning questions check whether you can pick the right tool and units, judge what counts as good evidence, predict how variables relate, and run the scientific method correctly. This lesson walks through each skill with how it is tested and short examples.","sections":[{"heading":"Measurement: choosing the right tool and unit","body":"The TEAS asks you to match a measurement to its correct tool and unit. Memorize these pairings.\n\n- Length or distance: ruler, meter stick, or tape measure; SI unit meters (m), also cm and mm.\n- Mass (amount of matter): balance (triple-beam or electronic); SI unit grams (g) or kilograms (kg). A scale measures weight, which depends on gravity; mass does not.\n- Volume of a liquid: graduated cylinder; unit liters (L) or milliliters (mL). For a solid, use water displacement.\n- Temperature: thermometer; unit degrees Celsius (C) for science, also Kelvin (K) and Fahrenheit (F).\n- Time: stopwatch or clock; unit seconds (s), minutes, hours.\n\nClassic test trap: do not use a scale for true mass, and do not use a beaker for precise volume (a graduated cylinder is more accurate)."},{"heading":"Reading scales and significant figures","body":"How it is tested: a picture of a graduated cylinder, ruler, or thermometer, and you must read the value, or you must report digits correctly.\n\nReading a graduated cylinder: read at eye level at the bottom of the meniscus (the curved dip in the liquid surface). Figure out what each unmarked line is worth first. If lines are 10 mL apart with 10 spaces, each line is 1 mL.\n\nSignificant figures show how precise a measurement is.\n- All nonzero digits count: 25.4 has 3.\n- Zeros between nonzeros count: 502 has 3.\n- Leading zeros never count: 0.0047 has 2.\n- Trailing zeros after a decimal count: 3.200 has 4.\n\nWhen estimating between the smallest marks, record one extra estimated digit. A ruler marked in mm lets you estimate to a tenth of a mm."},{"heading":"Valid explanations: logic and evidence","body":"How it is tested: you choose the best-supported explanation or spot a flawed one.\n\nA valid scientific explanation is supported by observable, measurable evidence, is logically consistent, and could be tested or disproven. Be suspicious of answers that rely on opinion, untestable claims, or a single anecdote.\n\nCorrelation vs causation is the most tested idea here. Two things changing together (correlation) does not prove one causes the other (causation). A third factor may drive both.\n\n- Example: ice cream sales and drowning deaths both rise in summer. Ice cream does not cause drowning; hot weather (a confounding variable) increases both. Only a controlled experiment can establish cause."},{"heading":"Predicting relationships and trends","body":"How it is tested: from a table or graph, predict the next value or describe how two variables relate.\n\nDirect (positive) relationship: as one variable increases, the other increases too. The line slopes upward. Example: more study hours, higher test score.\n\nInverse (negative) relationship: as one increases, the other decreases. The line slopes downward. Example: speed up and travel time goes down. For gases, Boyle's law is inverse: increase pressure, volume drops.\n\nExtrapolating means extending a trend beyond the data you have. If a plant grows about 2 cm per week for 4 weeks, predict roughly 10 cm at week 5. Interpolating is estimating between known points. Read the pattern, then continue it in the same direction and rate."},{"heading":"The scientific method and variables","body":"Steps: ask a question, form a hypothesis, experiment, collect and analyze data, draw a conclusion. A hypothesis is a testable, falsifiable prediction, often written as If... then...\n\nKnow the variable types cold:\n- Independent variable: what the researcher deliberately changes (the cause).\n- Dependent variable: what is measured in response (the effect; it depends on the independent variable).\n- Controlled variables (constants): everything kept the same so the test is fair.\n- Control group: the group with no treatment or a standard treatment, used for comparison.\n\nValid conclusions stay within the data and follow from the results; do not over-claim. Reproducibility means others can repeat the procedure and get similar results, which is what makes a finding trustworthy. A large sample size and a control group strengthen a study."},{"heading":"Example experiment with the variables labeled","body":"Question: Does fertilizer amount affect tomato plant height?\n\nHypothesis: If a tomato plant receives more fertilizer, then it will grow taller (up to a point).\n\nSetup: Five groups of plants get 0, 1, 2, 3, and 4 grams of fertilizer per week for 6 weeks. All plants get the same soil, pot size, water, sunlight, and tomato variety.\n\n- Independent variable: grams of fertilizer per week (what you change).\n- Dependent variable: plant height in cm (what you measure).\n- Controlled variables: soil, pot size, water, sunlight, plant type, time.\n- Control group: the 0-gram plants, used as the baseline for comparison.\n\nA valid conclusion compares treated groups to the control. If only the fertilized plants grew taller and everything else was held constant, you can reasonably link fertilizer to growth. Repeating the experiment and getting the same result confirms reproducibility."},{"heading":"Test-day tips","body":"- Match tool to measurement fast: graduated cylinder for volume, balance for mass, ruler for length, thermometer for temperature, stopwatch for time.\n- Read a graduated cylinder at the bottom of the meniscus, at eye level.\n- Leading zeros never count for sig figs; trailing zeros after a decimal do.\n- See two things moving together? Suspect correlation, not causation; look for a hidden third variable.\n- Independent = what you change; dependent = what you measure; it depends on the independent.\n- The control group gets no treatment and is your comparison baseline.\n- Direct = same direction; inverse = opposite directions.\n- A good conclusion never claims more than the data shows, and a good study can be reproduced."}]},
  {"section":"ENGLISH","topic":"conventions","title":"Conventions of Standard English","intro":"The Conventions of Standard English questions test the rules of spelling, punctuation, and sentence structure that make writing clear and correct. This lesson walks through each rule with a matched correct and incorrect example so you can recognize the right choice quickly on test day.","sections":[{"heading":"Spelling (common confusions)","body":"Many TEAS spelling items test words that sound alike but mean different things (homophones) or words people routinely misspell. The trick is to match the meaning to the spelling.\n\nWatch these high-frequency pairs:\n- their (possessive), there (place), they're (they are)\n- your (possessive), you're (you are)\n- its (possessive), it's (it is)\n- affect (usually a verb, to influence), effect (usually a noun, a result)\n- accept (to receive), except (to leave out)\n- principal (head of a school, or main), principle (a rule or belief)\n- patient (a noun for the person, or calm) vs patience (the quality)\n\nCorrect: The nurse recorded its effect on the patient's blood pressure.\nIncorrect: The nurse recorded it's affect on the patients blood pressure.\n\nAlso memorize commonly misspelled clinical and everyday words: separate, definitely, necessary, occurred, receive, embarrass, rhythm, occasion.\n\nCorrect: It is necessary to separate the two medications.\nIncorrect: It is neccessary to seperate the two medications."},{"heading":"End punctuation","body":"Every complete sentence needs an end mark. Choose it based on the sentence's purpose.\n- Period: a statement or a mild command.\n- Question mark: a direct question.\n- Exclamation point: strong emotion or a sharp command (use sparingly in formal writing).\n\nA common error is using a question mark for an indirect question (a statement that reports a question).\n\nCorrect: The doctor asked whether the patient had eaten.\nIncorrect: The doctor asked whether the patient had eaten?\n\nCorrect: Did the patient take the medication this morning?\nIncorrect: Did the patient take the medication this morning."},{"heading":"Commas with introductory words and phrases","body":"Place a comma after an introductory word, phrase, or dependent clause to separate it from the main sentence. This signals where the lead-in ends and the main idea begins.\n\nUse it after:\n- Transition or intro words: However, Therefore, First, Yes, Meanwhile\n- Introductory phrases: After the surgery, In the morning\n- Introductory dependent clauses: Because she was tired, When the alarm sounded\n\nCorrect: After the surgery, the patient rested quietly.\nIncorrect: After the surgery the patient rested quietly.\n\nCorrect: However, the lab results were normal.\nIncorrect: However the lab results were normal.\n\nNote: a very short intro phrase can sometimes skip the comma, but adding it is rarely wrong on the test."},{"heading":"Commas joining independent clauses and avoiding comma splices","body":"An independent clause is a complete thought that could stand alone as a sentence. When you join two independent clauses, use a comma BEFORE a coordinating conjunction. Remember the conjunctions with FANBOYS: for, and, nor, but, or, yet, so.\n\nCorrect: The patient felt dizzy, so the nurse checked her blood pressure.\nIncorrect: The patient felt dizzy so the nurse checked her blood pressure.\n\nA comma splice is the error of joining two independent clauses with ONLY a comma and no conjunction. Fix it three ways: add a conjunction, use a semicolon, or make two sentences.\n\nIncorrect (comma splice): The medication was ready, the nurse administered it.\nCorrect: The medication was ready, and the nurse administered it.\nCorrect: The medication was ready; the nurse administered it.\nCorrect: The medication was ready. The nurse administered it.\n\nWarning: words like however, therefore, and thus are NOT FANBOYS. A comma before them between two clauses creates a splice; use a semicolon instead.\nIncorrect: She was tired, however she finished her shift.\nCorrect: She was tired; however, she finished her shift."},{"heading":"Commas with nonessential vs essential clauses","body":"A nonessential (nonrestrictive) element adds extra information you could remove without changing the core meaning. Set it off with commas. An essential (restrictive) element is needed to identify what you mean, so it takes NO commas.\n\nTip: if removing the clause still leaves the sentence clear and specific, it is nonessential, so use commas. Use 'which' (with commas) for nonessential and 'that' (no commas) for essential.\n\nCorrect (nonessential): My oldest brother, who lives in Texas, is a nurse.\nHere there is only one oldest brother, so the clause is extra. Commas are correct.\n\nCorrect (essential): The nurse who administered the vaccine signed the chart.\nHere 'who administered the vaccine' identifies which nurse, so no commas.\n\nIncorrect: The patient, who refused treatment, was discharged. (Wrong if the clause is needed to identify which patient; then it should have no commas.)"},{"heading":"Commas separating coordinate adjectives","body":"Coordinate adjectives are two or more adjectives that independently and equally describe the same noun. Separate them with a comma. Adjectives are coordinate if you can swap their order or insert 'and' between them and the sentence still sounds right.\n\nCorrect: She was a calm, confident nurse.\nTest: 'a confident, calm nurse' and 'calm and confident nurse' both work, so the comma is correct.\n\nDo NOT use a comma when the adjectives are cumulative (they build on each other and cannot be reordered or joined with 'and').\n\nCorrect: He wore bright blue scrubs.\nIncorrect: He wore bright, blue scrubs.\nTest: 'blue bright scrubs' and 'bright and blue scrubs' sound wrong, so no comma."},{"heading":"Commas in a series","body":"When you list three or more items, separate them with commas. The final comma before 'and' or 'or' is called the Oxford (serial) comma. The TEAS treats including it as correct, and it often prevents confusion.\n\nCorrect: The cart held gloves, gauze, and tape.\nIncorrect: The cart held gloves gauze and tape.\n\nThe series can be words, phrases, or short clauses.\nCorrect: She checked the chart, called the doctor, and updated the family.\n\nThe Oxford comma can prevent a misread:\nClearer: We thanked the nurses, Dr. Lee, and the aide.\nConfusing without it: We thanked the nurses, Dr. Lee and the aide. (sounds like the nurses are named Dr. Lee and the aide)"},{"heading":"Punctuating quotations","body":"Put quotation marks around a speaker's exact words. Use a comma to introduce or follow the quote, and keep periods and commas INSIDE the closing quotation mark.\n\nCorrect: The nurse said, \"Please rate your pain.\"\nIncorrect: The nurse said \"Please rate your pain\".\n\nWhen the quote comes first, the comma goes inside the closing quote before the attribution.\nCorrect: \"Please rate your pain,\" the nurse said.\nIncorrect: \"Please rate your pain\", the nurse said.\n\nQuestion marks and exclamation points go inside the quotes if they belong to the quoted material, and outside if they belong to the whole sentence.\nCorrect: She asked, \"Are you comfortable?\"\nCorrect: Did she really say, \"I feel fine\"?"},{"heading":"Colons","body":"A colon introduces a list, an explanation, or a quotation, but only after a complete independent clause. Do not put a colon right after a verb or preposition.\n\nCorrect: Bring three items: a pen, a chart, and a thermometer.\nIncorrect: Bring: a pen, a chart, and a thermometer.\nIncorrect: The three items are: a pen, a chart, and a thermometer. (Here 'are' should lead directly into the list, so drop the colon.)\n\nA colon can also introduce an explanation or emphasis of the first clause.\nCorrect: The result was clear: the patient needed rest.\n\nDo not confuse the colon with the semicolon. A semicolon joins two related independent clauses.\nCorrect: The shift was long; everyone was exhausted."},{"heading":"Parentheses","body":"Parentheses enclose extra, nonessential information such as an aside, a clarification, or an example. The sentence must still read correctly if you remove the parentheses and everything inside them.\n\nCorrect: The medication (a common antibiotic) was given at noon.\nIncorrect: The medication a common antibiotic was given at noon.\n\nPunctuation rules:\n- Put end punctuation OUTSIDE the closing parenthesis when the parentheses are part of a larger sentence.\n- Do not place a comma right before an opening parenthesis.\n\nCorrect: She arrived early (around 6 a.m.).\nIncorrect: She arrived early, (around 6 a.m.)."},{"heading":"Types of sentences","body":"Sentences are classified by how many independent and dependent clauses they contain.\n- Simple: one independent clause. Example: The nurse charted the vitals.\n- Compound: two or more independent clauses joined by a comma plus FANBOYS or a semicolon. Example: The nurse charted the vitals, and the doctor reviewed them.\n- Complex: one independent clause plus at least one dependent clause. Example: After she charted the vitals, the doctor reviewed them.\n- Compound-complex: two or more independent clauses plus at least one dependent clause. Example: After she charted the vitals, the nurse left, and the doctor reviewed them.\n\nCorrect (compound): The alarm sounded, so the team responded.\nIncorrect (mislabeled): Calling 'The alarm sounded so the team responded' a correct compound sentence; it is missing the comma before 'so.'\n\nKnow the difference between a coordinating conjunction (joins equals: FANBOYS) and a subordinating conjunction (starts a dependent clause: because, although, when, if, since, after, while)."},{"heading":"Correct sentence structure: fragments and run-ons","body":"A complete sentence needs a subject, a verb, and a complete thought. Two common errors break this rule.\n\nFragment: an incomplete piece punctuated as a sentence (missing a subject, a verb, or a complete thought).\nIncorrect (fragment): Because the patient was dehydrated.\nCorrect: Because the patient was dehydrated, the nurse started an IV.\n\nRun-on (fused sentence): two independent clauses jammed together with no punctuation or conjunction.\nIncorrect (run-on): The patient was dehydrated the nurse started an IV.\nCorrect: The patient was dehydrated, so the nurse started an IV.\nCorrect: The patient was dehydrated; the nurse started an IV.\n\nRemember: a comma alone cannot fix a run-on (that creates a comma splice). You need a conjunction, a semicolon, or a period."},{"heading":"Subject-verb agreement (including intervening phrases)","body":"The verb must agree with its subject in number: singular subject takes a singular verb, plural subject takes a plural verb. The challenge is words that come BETWEEN the subject and verb; ignore them when choosing the verb.\n\nCorrect: The box of gloves is on the shelf. (subject = box, singular)\nIncorrect: The box of gloves are on the shelf.\n\nIgnore phrases beginning with 'of,' 'with,' 'along with,' and 'as well as.'\nCorrect: The nurse, along with two aides, was on duty.\nIncorrect: The nurse, along with two aides, were on duty.\n\nWatch indefinite pronouns: each, every, everyone, everybody, someone, nobody, neither, and either are singular.\nCorrect: Each of the patients needs a wristband.\nIncorrect: Each of the patients need a wristband.\n\nFor 'either...or' and 'neither...nor,' the verb agrees with the nearer subject.\nCorrect: Neither the doctor nor the nurses were available."},{"heading":"Misplaced and dangling modifiers","body":"A modifier should sit next to the word it describes. When it is too far away (misplaced) or has nothing logical to describe (dangling), the sentence says something unintended.\n\nMisplaced modifier: the describing word is in the wrong spot.\nIncorrect: The nurse handed a cup to the patient that was full of water. (sounds like the patient was full of water)\nCorrect: The nurse handed a cup that was full of water to the patient.\n\nDangling modifier: an introductory phrase whose true subject is missing from the main clause.\nIncorrect: Walking into the room, the chart was reviewed. (the chart cannot walk)\nCorrect: Walking into the room, the nurse reviewed the chart.\n\nFix: make sure the word right after an introductory phrase is the thing performing the action."},{"heading":"Test-day tips","body":"- Read the whole sentence, then say it in your head; many errors are easier to hear than to see.\n- For commas, ask whether each part is essential. If you can remove a chunk and the sentence still makes sense, set it off with commas.\n- Check that the word right after an introductory phrase is who or what did the action; this catches dangling modifiers.\n- Mentally strip out 'of,' 'with,' and 'as well as' phrases to test subject-verb agreement.\n- To catch comma splices and run-ons, see if each side of a comma could stand alone as a sentence. If both can, you need a conjunction, a semicolon, or a period.\n- Match end punctuation to purpose: statements get periods, direct questions get question marks; indirect questions get periods.\n- Keep periods and commas inside closing quotation marks.\n- Use a colon only after a complete clause, never right after a verb or preposition.\n- When two answers look identical except for punctuation, the difference is the whole point; slow down and test that exact mark."}]},
  {"section":"ENGLISH","topic":"knowledge-language","title":"Knowledge of Language","intro":"Knowledge of Language questions test whether you can match writing to its purpose, audience, and structure, and whether you can tighten sentences for clarity. This lesson walks through each skill, how the TEAS frames it, and a worked example you can model on test day.","sections":[{"heading":"Identifying genre and types of writing","body":"Genre means the category a passage belongs to based on its main purpose. On the TEAS you are given a short passage or a single sentence and asked to name the type of writing. The four types tested most often are:\n\n- Narrative: tells a story or relates events, often with characters, time order, and personal voice. Example: \"The night before my first clinical, I could not sleep, so I reread my notes until dawn.\"\n- Expository: explains or informs with facts, definitions, and steps. Example: \"The heart has four chambers: two atria and two ventricles.\"\n- Persuasive: argues a position and tries to convince the reader, often using opinion words and calls to action. Example: \"Hospitals must hire more nurses now because understaffing endangers patients.\"\n- Technical: gives precise instructions or specialized procedures, often in steps with exact measurements. Example: \"Administer 0.5 mL intramuscularly, then document the site and time.\"\n\nHow it is tested: a question may quote a sentence and ask \"This sentence is an example of which type of writing?\" Match the main purpose (tell a story, explain, persuade, instruct) to the label. Watch for clue words: \"should/must/best\" signals persuasive; steps and measurements signal technical; \"first I, then I\" signals narrative; neutral facts signal expository."},{"heading":"Identifying the intended audience","body":"The intended audience is the group the writer expects to read the text. You identify it by looking at vocabulary, level of detail, and assumed background knowledge.\n\n- Specialized vocabulary with no definitions signals an expert audience. Example: \"Titrate the dopamine drip per the MAP protocol\" assumes trained nurses.\n- Defined terms, simple words, and reassuring tone signal a general or lay audience. Example: \"Your IV is the small tube in your arm that gives you fluids and medicine\" is written for patients.\n- Playful word choice and basic concepts signal a young audience.\n\nHow it is tested: a question gives a passage and asks \"Who is the intended audience?\" or \"This passage was most likely written for whom?\" Decide whether the writer assumes the reader already knows the jargon (experts) or explains it (general public). The amount of explanation is your strongest clue."},{"heading":"Matching language and tone to audience","body":"Tone is the writer's attitude, and the right tone depends on the audience and situation. The TEAS focuses on the difference between formal and informal language.\n\n- Formal language: complete sentences, no slang, no contractions, professional and objective. Used for textbooks, research, charting, and emails to instructors or supervisors. Example: \"The patient reported moderate discomfort following the procedure.\"\n- Informal language: conversational, contractions, slang, casual. Used for texts to friends or personal blogs. Example: \"The patient was kinda sore after, no big deal.\"\n\nHow it is tested: a question describes a situation (for example, emailing a professor or writing a clinical report) and asks which sentence uses appropriate language. Choose formal for academic, professional, and medical settings. Also watch for consistency: a passage should not mix a casual phrase into an otherwise formal paragraph.\n\nExample question: For a note in a patient's medical chart, the best choice is \"The wound shows no signs of infection,\" not \"The wound looks totally fine.\""},{"heading":"Stages of the writing process","body":"The TEAS expects you to know the five stages in order and what happens in each. Memorize the sequence: prewriting, drafting, revising, editing, publishing.\n\n- Prewriting: brainstorming, choosing a topic, listing ideas, outlining, and researching. Nothing is written in full sentences yet.\n- Drafting: writing the first full version, getting ideas into paragraphs without worrying about perfection.\n- Revising: improving content and organization. You add, cut, reorder, and clarify ideas. Big-picture changes happen here.\n- Editing: fixing surface errors such as grammar, spelling, punctuation, and capitalization. Small, sentence-level corrections.\n- Publishing: sharing the finished piece with its audience, such as turning it in or posting it.\n\nHow it is tested: a question describes an action and asks which stage it belongs to. The most common trap is confusing revising with editing. Remember: revising changes ideas and structure; editing fixes mechanics. Example: \"A student rearranges paragraphs so the argument flows better.\" That is revising, not editing."},{"heading":"Parts of a paragraph","body":"A well-built paragraph has three parts, and the TEAS asks you to identify each.\n\n- Topic sentence: states the main idea, usually first. Example: \"Handwashing is the single most effective way to prevent infection.\"\n- Supporting details: sentences in the middle that explain, prove, or give examples for the topic sentence. Example: \"Studies show proper handwashing cuts hospital infections by up to half.\"\n- Concluding sentence: wraps up the paragraph and often restates the main idea in new words. Example: \"For these reasons, clean hands protect every patient.\"\n\nHow it is tested: a question may show a paragraph and ask \"Which sentence is the topic sentence?\" or \"Which sentence best concludes this paragraph?\" The topic sentence is the broadest statement; supporting details are specific; the conclusion signals closure with words like \"therefore,\" \"in short,\" or \"for these reasons.\""},{"heading":"Identifying unrelated or off-topic sentences","body":"A strong paragraph stays unified: every sentence supports the topic sentence. The TEAS tests this by inserting one sentence that does not belong and asking you to find it.\n\nHow it is tested: a question says \"Which sentence does not belong in the paragraph?\" or \"Which sentence is off topic?\" Your method:\n\n- Find the topic sentence and pin down the main idea.\n- Check each remaining sentence: does it directly support that idea? If not, it is the off-topic one.\n\nExample: \"Regular exercise improves health. It strengthens the heart and lowers blood pressure. It also helps control weight. My cousin just bought a new car.\" The sentence about the car has nothing to do with exercise and health, so it is the unrelated sentence.\n\nTip: an off-topic sentence may be true and well-written, but it still breaks the paragraph's focus. Judge by relevance to the topic, not by whether the sentence is correct."},{"heading":"Grammar for clarity and conciseness","body":"This skill asks you to choose the clearest, tightest version of a sentence. Good writing says the most with the fewest words while staying correct and easy to understand.\n\nWays to improve a sentence:\n\n- Cut redundancy. \"The two twins\" becomes \"the twins.\" \"Combine together\" becomes \"combine.\"\n- Remove wordy phrases. \"Due to the fact that\" becomes \"because.\" \"In order to\" becomes \"to.\"\n- Prefer active voice. \"The medication was administered by the nurse\" becomes \"The nurse administered the medication.\"\n- Fix misplaced or unclear modifiers so the sentence cannot be misread. \"Walking to work, the rain soaked her\" should be \"Walking to work, she got soaked by the rain.\"\n\nHow it is tested: a question gives a wordy or awkward sentence and four rewrites, asking which is clearest and most concise. Choose the option that keeps the full meaning, fixes any grammar error, and uses the fewest unnecessary words. Beware of choices that are short but drop important information, and choices that are correct but padded."},{"heading":"Test-day tips","body":"- For genre questions, ask one question: what is the writer mainly trying to do? Tell a story (narrative), explain (expository), convince (persuasive), or instruct (technical).\n- Judge audience by how much the writer explains. Lots of defined terms means a general or lay audience; unexplained jargon means experts.\n- Default to formal language for any academic, professional, or medical setting, and watch for one casual phrase that breaks the tone.\n- Keep the writing stages in order and remember the key split: revising changes ideas and structure, editing fixes grammar and spelling.\n- For paragraph-part questions, the topic sentence is the broadest; the conclusion uses closure words like \"therefore\" or \"in short.\"\n- To find the off-topic sentence, lock onto the main idea first, then remove the sentence that does not support it, even if it is true.\n- For clarity questions, pick the shortest answer that keeps all the meaning and contains no grammar error. When two options seem close, choose the more concise one unless it loses information."}]},
  {"section":"ENGLISH","topic":"vocabulary","title":"Vocabulary Acquisition","intro":"On the TEAS, you will meet words you have never seen before, especially medical and scientific terms. Instead of memorizing endless lists, you can break unfamiliar words into parts and read the surrounding sentence for clues to unlock meaning on the spot.","sections":[{"heading":"How word attack works","body":"Most academic and medical English words are built from three kinds of parts: a prefix at the front, a root in the middle, and a suffix at the end. If you know what a part means, you can predict the meaning of the whole word even when you have never studied it.\n\nExample: the word 'dermatitis' breaks into 'derm' (skin) plus '-itis' (inflammation), so it means inflammation of the skin. The word 'antibacterial' breaks into 'anti-' (against) plus 'bacteria,' so it means working against bacteria.\n\nStrategy for test day: when a word looks hard, slow down and chop it into pieces. Decode each piece, then put the meaning back together. If you are still unsure, use the sentence around the word (context clues), which you will practice later in this lesson."},{"heading":"Using prefixes to determine word meaning","body":"A prefix is added to the front of a word and usually tells you direction, time, position, or whether something is negative. Learn these high-frequency prefixes and the change each one makes.\n\n- un- : not or reverse (unable, undo)\n- re- : again or back (rebuild, return)\n- pre- : before (preview, prenatal)\n- anti- : against or opposing (antibiotic, antiseptic)\n- sub- : under or below (submerge, subcutaneous)\n- inter- : between or among (interact, intervenous between vessels is intervascular)\n- mal- : bad or wrong (malignant, malnourished)\n- bene- : good or well (benefit, benign)\n- circum- : around (circumference, circumvent)\n- ante- : before (antecedent, anteroom)\n\nWatch the pair ante- (before) versus anti- (against); they look alike but mean very different things. 'Antenatal' means before birth, while 'antibody' means a defender against invaders."},{"heading":"Using suffixes to determine word meaning","body":"A suffix is added to the end of a word. Suffixes often tell you the part of speech (noun, adjective) and add a category of meaning such as a condition, a field of study, or a person who does something.\n\n- -ology : the study of (biology, cardiology)\n- -phobia : fear of (claustrophobia, hydrophobia)\n- -able / -ible : capable of or able to be (readable, edible)\n- -ous : full of or having (dangerous, poisonous)\n- -tion : the act, state, or result of (action, infection)\n- -ist : a person who does or specializes in (artist, pharmacist)\n- -itis : inflammation (arthritis, bronchitis)\n\nMedical note: -itis (inflammation) is everywhere in nursing vocabulary. 'Tonsillitis' is inflammation of the tonsils, and 'appendicitis' is inflammation of the appendix. Spotting the suffix tells you the word names a swelling or irritation."},{"heading":"Using common root words to determine word meaning","body":"The root is the core of the word and carries its central meaning. Prefixes and suffixes attach to roots. Knowing common roots, many from Greek and Latin, lets you decode whole families of words.\n\n- aqua : water (aquarium, aquatic)\n- chrono : time (chronological, chronic)\n- dict : say or speak (dictate, predict)\n- spect : look or see (inspect, spectator)\n- bio : life (biology, biopsy)\n- geo : earth (geography, geology)\n- cardi : heart (cardiac, cardiology)\n- derm : skin (dermatology, epidermis)\n- neuro : nerve or nervous system (neurology, neuron)\n\nCombine parts to confirm meaning. 'Cardiologist' is cardi (heart) plus -ology (study of) plus -ist (a person who), so it is a person who studies and treats the heart. 'Neuritis' is neuro (nerve) plus -itis (inflammation), so it is inflammation of a nerve."},{"heading":"Using context clues: definition and synonym","body":"Sometimes the sentence itself defines or restates a hard word. There are two helpful types here.\n\nDefinition clue: the sentence directly explains the word, often after a comma, a dash, or words like 'is,' 'means,' or 'that is.' Example: 'The patient had tachycardia, meaning a rapid heart rate.' The phrase after the comma tells you tachycardia is a fast heartbeat.\n\nSynonym clue: a nearby word means roughly the same thing, often signaled by 'or,' 'also called,' 'similarly,' or 'in other words.' Example: 'The wound was sutured, or stitched closed, by the nurse.' The synonym 'stitched closed' shows that sutured means stitched.\n\nHabit to build: when you hit an unknown word, look right around it for a restatement before you guess."},{"heading":"Using context clues: antonym and example","body":"Two more context clue types work by contrast or by illustration.\n\nAntonym clue (also called contrast): a nearby word means the opposite, signaled by 'but,' 'however,' 'unlike,' 'whereas,' or 'on the other hand.' Example: 'Unlike her usually loquacious sister, Maria was quiet and said little.' The contrast with 'quiet and said little' tells you loquacious means talkative.\n\nExample clue: the sentence gives specific instances, signaled by 'such as,' 'for example,' 'including,' or 'like.' Example: 'Citrus fruits, such as oranges, lemons, and limes, are high in vitamin C.' The listed fruits show that citrus refers to that tart, vitamin C rich fruit group.\n\nTip: signal words are your friends. Train your eye to notice 'but,' 'such as,' 'or,' and 'meaning,' because each one points to a clue about a nearby word."},{"heading":"Test-day tips","body":"- Break the word apart. Decode the prefix, root, and suffix, then reassemble the meaning.\n\n- Read the whole sentence, and the one before and after, for definition, synonym, antonym, or example clues.\n\n- Hunt for signal words: 'means' and 'is' signal definitions; 'or' and 'also called' signal synonyms; 'but,' 'unlike,' and 'however' signal antonyms; 'such as' and 'for example' signal examples.\n\n- Do not confuse look-alike parts: ante- (before) versus anti- (against), and -able versus -ible both mean capable of.\n\n- Lean on medical patterns you know: -itis is inflammation, -ology is the study of, cardi is heart, derm is skin, neuro is nerve.\n\n- If two answer choices seem close, plug each one back into the sentence and keep the one that fits the tone and the clues.\n\n- Eliminate first. Cross out choices that clash with a prefix or with a contrast word, then choose among what remains."}]},
];

export function getLesson(section: string, topic: string): Lesson | undefined {
  return LESSONS.find((l) => l.section === section && l.topic === topic);
}
